1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	function basePremiumFor(item: { type: string }): number {
12	  return BASE_PREMIUM_BY_TYPE[item.type];
13	}
14	
15	export function quote(_customer: { yearsWithMHPCO: number }, items: { type: string }[]): number {
16	  const itemsTotal = items.length === 0 ? 0 : basePremiumFor(items[0]);
17	  return itemsTotal + PROCESSING_FEE;
18	}
19	
20	export function claim(): number {
21	  return undefined as unknown as number;
22	}
